const params = $('Extract Audit Parameters').first().json;
const mobile = $('PageSpeed Insights (Mobile)').first().json;
const desktop = $('PageSpeed Insights (Desktop)').first().json;

function getScore(data, category) {
  try {
    const score = data.lighthouseResult?.categories?.[category]?.score;
    return score !== undefined ? Math.round(score * 100) : null;
  } catch (e) { return null; }
}

const mobilePerf = getScore(mobile, 'performance');
const desktopPerf = getScore(desktop, 'performance');
const seoScore = getScore(mobile, 'seo');
const accessibilityScore = getScore(mobile, 'accessibility');

const lcp = mobile.lighthouseResult?.audits?.['largest-contentful-paint']?.displayValue || null;
const fid = mobile.lighthouseResult?.audits?.['total-blocking-time']?.displayValue || null;
const cls = mobile.lighthouseResult?.audits?.['cumulative-layout-shift']?.displayValue || null;

return [{
  json: {
    website_url: params.website_url,
    requester_email: params.requester_email,
    requester_name: params.requester_name,
    mobile_performance: mobilePerf,
    desktop_performance: desktopPerf,
    seo_score: seoScore,
    accessibility_score: accessibilityScore,
    core_web_vitals: { lcp, fid, cls }
  }
}];

