const scanData = $('Merge PageSpeed Scores').first().json;
const claudeResponse = $input.item.json;

let analysis = {};
try {
  const content = claudeResponse.content?.[0]?.text || '{}';
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  analysis = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch (e) {
  analysis = { website_score: 50, summary: 'Audit unavailable', audit_teaser: 'We found several areas for improvement.' };
}

const auditData = {
  ...analysis,
  raw_scores: {
    mobile_performance: scanData.mobile_performance,
    desktop_performance: scanData.desktop_performance,
    pagespeed_seo: scanData.seo_score,
    accessibility: scanData.accessibility_score,
    core_web_vitals: scanData.core_web_vitals
  }
};

return [{
  json: {
    website_url: scanData.website_url,
    requester_email: scanData.requester_email,
    requester_name: scanData.requester_name,
    audit_data: auditData,
    teaser: analysis.audit_teaser || 'We found several improvement opportunities.',
    pain_point_summary: analysis.pain_point_summary || ''
  }
}];
